sp_widget.client_script:
function($scope, $location, $rootScope,spModal,$uibModal, spUtil) {
	//------------------------------------------------------------------------------------------------------------------------
	// COMPANY: DISCOVER TECHNOLOGIES
	// CUSTOMIZED BY: KARINA TORRES
	// RECURSIVE GRAPHICAL TREE FOR PROCESS TEMPLATE
	// HELPUL LINKS: https://gojs.net/latest/intro/textblocks.html
	//------------------------------------------------------------------------------------------------------------------------

	//------------------------------------------------------------------------------------------------------------------------
	// 2.5.21 | 09.08.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
	var node_active_bg = '#33738e';
	var node_inactive_bg = '#787878';
	var node_selected_border = '#FFD247';

	// STRY0108231
	var icon_normal_stroke = "white";
	var icon_hover_stroke = "#F00";
	var icon_warning_stroke = "#FF0";
  var toolTipBackgroundColor = '#FFFFFF'; // "#C5C5C5"
  var tooltipTextColor = '#3A3F51';

	// settings for the list widgets use these objects
	var icon_opacity_normal = 1.00;
	var icon_opacity_hover = 0.75;
	var use_user_image = 'USE_USER_IMAGE';
	var informationFormwidgetObject = {};
	informationFormwidgetObject.modalType = "form";
	informationFormwidgetObject.title = ''; // needs data to set
	informationFormwidgetObject.table = 'x_153465_discovert_discover_office_hierarchy';
	informationFormwidgetObject.sys_id = '';  // needs key added inline
	informationFormwidgetObject.view = 'Default View';	
	var subOUListwidgetObject = {};
	subOUListwidgetObject.modalType = "list";
	subOUListwidgetObject.title = ''; // needs data to set
	subOUListwidgetObject.o = 'level_order,office_name';
	subOUListwidgetObject.d = 'asc';
	subOUListwidgetObject.table = 'x_153465_discovert_discover_office_hierarchy';
	subOUListwidgetObject.filter = 'parent=';  // needs key added inline
	subOUListwidgetObject.view = 'Default View';
	var membersOUListwidgetObject = {};
	membersOUListwidgetObject.modalType = "list";
	membersOUListwidgetObject.title = ''; // needs data to set
	membersOUListwidgetObject.o = 'office_member';
	membersOUListwidgetObject.d = 'asc';
	membersOUListwidgetObject.table = 'x_153465_discovert_discover_office_members';
	membersOUListwidgetObject.filter = 'discover_office_hierarchy=';  // needs key added inline
	membersOUListwidgetObject.view = 'Default View';
	var contactsOUListwidgetObject = {};
	contactsOUListwidgetObject.modalType = "list";
	contactsOUListwidgetObject.title = ''; // needs data to set
	contactsOUListwidgetObject.o = 'u_tasker_contact';
	contactsOUListwidgetObject.d = 'asc';
	contactsOUListwidgetObject.table = 'x_153465_discovert_organizational_contacts';
	contactsOUListwidgetObject.filter = 'u_contact_ou=';  // needs key added inline
	contactsOUListwidgetObject.view = 'Default View';	
	var OUReportwidgetObject = {};
	OUReportwidgetObject.modalType = "report";
	OUReportwidgetObject.title = ''; // needs data to set
	OUReportwidgetObject.o = 'title';
	OUReportwidgetObject.d = 'asc';
	OUReportwidgetObject.table = 'sys_report';
	OUReportwidgetObject.filter = 'primary_assignee=';  // needs key added inline
	OUReportwidgetObject.view = 'Default View';
	var relatedTaskOUListwidgetObject = {};
	relatedTaskOUListwidgetObject.modalType = "list";
	relatedTaskOUListwidgetObject.title = ''; // needs data to set
	relatedTaskOUListwidgetObject.o = 'number';
	relatedTaskOUListwidgetObject.d = 'desc';
	relatedTaskOUListwidgetObject.table = 'x_153465_discovert_route_task_instance';
	relatedTaskOUListwidgetObject.filter = '	primary_assignee=';  // needs key added inline
	relatedTaskOUListwidgetObject.view = 'Default View';		
	var requestChangeFormwidgetObject = {};
	requestChangeFormwidgetObject.modalType = "form";
	requestChangeFormwidgetObject.title = ''; // needs data to set
	requestChangeFormwidgetObject.table = 'x_153465_discovert_tasker_requests';
	requestChangeFormwidgetObject.sys_id = -1;
	requestChangeFormwidgetObject.u_ou_parent=''; // needs key added inline
	requestChangeFormwidgetObject.view = 'ou_requesttop';	

	var createNewFormwidgetObject = {};
	createNewFormwidgetObject.modalType = "form";
	createNewFormwidgetObject.title = ''; // needs data to set
	createNewFormwidgetObject.table = 'x_153465_discovert_discover_office_hierarchy';
	createNewFormwidgetObject.sys_id = -1; 
	createNewFormwidgetObject.parent=''; // needs key added inline
	createNewFormwidgetObject.view = 'Simple';	
	//------------------------------------------------------------------------------------------------------------------------

	// RJ -ET - Story 4
	var c = this;

	c.data.topIconOpacity = c.data.isFullScreen? icon_opacity_normal:0.0;

	// STRY0096158 - ORG - Template Tree Min Size to avoid cutting off tool tip
	var  diagramMinHeight = 150;
	c.data.topOU="";
	// STRY0074597
	setOUPicker();

	// RJ -ET - Story 4
	var diagram;
	var display_id = $location.search().sys_id;
	// RJ -ET - Story 4
	// if no ID on URL, use the current id
	if (!display_id && c.data.id){
		display_id = c.data.id;
		broadcastTopNodeChange(display_id);
	}


	// STRY0078258 - use record watcher to keep grid synced
	spUtil.recordWatch($scope, "x_153465_discovert_discover_office_hierarchy", "",
	function(name) {
		var refreshDiagram = false;
		if(name.data.operation=="insert" || name.data.operation == "delete")
			refreshDiagram = true;
		else if(name.data.changes.includes("office_name")  ||
						name.data.changes.includes("office_abbreviation") ||
						name.data.changes.includes("active") || 
						name.data.changes.includes("level") ||
						name.data.changes.includes("parent") ||
						name.data.changes.includes("u_ou_hierarchy_administrators") ||
						name.data.changes.includes("tasking_authorities") ||
						name.data.changes.includes("u_outstanding_request_count")
					 ){
			refreshDiagram = true;			
		}
		if(refreshDiagram){
			spUtil.update($scope).then(function() {
				drawTree();
			})
		}
	});

	function broadcastTopNodeChange(topId) {
		var evt = {};
			evt.sys_id = topId;
			evt.table = 'x_153465_discovert_discover_office_hierarchy';
			// RJ -ET - Story 4
			evt.parent = '';
			$rootScope.$broadcast('$sp.list.click', evt);
		}
		// STRY0074597
		$scope.topOnlyCheck = function() {
			setOUPicker();
		}
		// STRY0074597
		function setOUPicker(){
			if(c.data.topOnly){
				c.data.OUPicker_displayFields='office_abbreviation,office_name';
				c.data.OUPicker_searchFields = 'office_abbreviation,office_name';
				c.data.OUPicker_query='active=true^parentISEMPTY';
			}else{
				c.data.OUPicker_displayFields='office_level,office_abbreviation,office_name';
				c.data.OUPicker_searchFields = 'office_level,office_abbreviation,office_name';
				c.data.OUPicker_query='active=true';
			}
		}

		$scope.topOU={
			displayValue: c.data.office_abbreviation + c.data.office_name,
			value: c.data.sys_id,
			name: 'topOU'
		};
		$scope.$on("field.change",function(evt,params){
			c.data.topOU = $scope.topOU.value;
			display_id = c.data.topOU;
			c.server.update().then(function(){
				drawTree();
			});
			broadcastTopNodeChange(display_id);
		})

		$scope.expandGraph = function(){
			spModal.open({
				title: "",
				backdrop:'static',
				widget: 'discovertasker-officehierarchy',
				size: 'lg',
				// STRY0074597
				widgetInput: {topOU:$scope.topOU.value,
					topOnly:c.data.topOnly
				},
				buttons:[]
			});
		}
		// STRY0074663
		$scope.$on('sp.form.record.updated', function(evt, item) {
			/* update model after return from modal */
			c.server.update().then(function(){
				drawTree();
			});
		});

		// RJ -ET - Story 4
		// STRY0093948 - the tasker form with tab is rasing this as a rootscope broadcast, updated to catch
		$rootScope.$on('$taskerTabbedForm.drillDownList.click', function(e, parms) {
			c.data.sys_id = parms.sys_id;
			// STRY0074663 Only rebroadcast if the node changed
			if(display_id != parms.sys_id){
				display_id = parms.sys_id;
				// Select the node using the sys_id parameter supplied.
				var node_select = diagram.findNodeForKey(display_id);
				diagram.select(node_select);
			}

		})

		function nodeSelectionChanged(node) {
			var evt = {};
				var d = node.data;
				evt.sys_id = d.sys_id;
				if (evt.sys_id == display_id)  // get called twice by gojs
					return;

				evt.table = d.sys_class_name || d.table;
				// RJ -ET - Story 4
				evt.parent = d.parent;
				display_id = evt.sys_id;
				$location.search('table', evt.table).search('sys_id', evt.sys_id).search('spa', 1);
				$rootScope.$broadcast('$sp.list.click', evt);

				// STRY0072032
				if(c.data.isSystemTreeOrientationVertical){
					diagram.centerRect(node.actualBounds);
				}
			}

			$scope.page = {
				displayValue: $scope.data.title,
				value: $scope.data.id,
				name: 'page'
			};

			$scope.$on("field.change", function(evt, parms) {
				if (parms.field.name == 'page')
					changePage(parms.newValue);
			});

			function changePage(p){
				var path = $location.path();
				var searchParms = $location.search();
				$location.search({id: searchParms.id, p: p});
				}


	// STRY0108231
	function toolTipDataListJSON(textHeader, bindingList) {
		var toolTip;
		var underline = '_';

		var $go = go.GraphObject.make; // for conciseness in defining templates
		var toolDataListJSON = 
				$go(go.Adornment, "Spot", "Auto",
						$go(go.Shape, "RoundedRectangle", {fill: toolTipBackgroundColor}),
						$go(go.Panel, {width:300},
								$go(go.Panel, "Vertical", {defaultAlignment: go.Spot.Left},
										$go(go.Panel, {defaultAlignment: go.Spot.Left},
												$go(go.TextBlock, 
														textHeader, 
														{textAlign:"left", margin:4, background: toolTipBackgroundColor}
													 ),
												$go(go.TextBlock, 
														underline.repeat(100), 
														{opacity: 0.5, stroke: "#999999", textAlign:"left", margin: 4, background: toolTipBackgroundColor}
													 )
											 ),
										$go(go.Panel, {defaultAlignment: go.Spot.Left},
												$go(go.Panel, "Table", new go.Binding("itemArray", bindingList),
														{ margin: 4,
														 defaultAlignment: go.Spot.Left,
														 itemTemplate:
														 $go(go.Panel, "TableRow",
																 {defaultAlignment: go.Spot.Left},
																 $go(go.TextBlock, new go.Binding("text", "displayName"),
																		 { column: 0, 
																			textAlign:"left",
																			background: toolTipBackgroundColor
																		 }
																		)
																)
														})
											 )
									 )
							 )
					 );
		return toolDataListJSON;
	}

	function addImage(imgSrc, opacity, toolTiptextHeader, toolTipBindingList) {
		var $go = go.GraphObject.make; // for conciseness in defining templates
// NOTE: put go.picture in a function and pass what you need to clean this up

		// STRY0101474 - if the image wasn't laoded, don't add the image NOTE: we may wat to put placeholder here IF it is defined to keep the space
		if(imgSrc == undefined){
			imgSrc = '';
		}
		var imageJSON =
			$go(go.Picture, 
				{margin: new go.Margin(5, 3, 5, 3),
				 alignment: go.Spot.TopRight,
				 source: imgSrc,
				 opacity: opacity}, 
					new go.Binding("opacity", toolTipBindingList, function(data){
														var lOpacity;
														if(toolTipBindingList == ''){
															// for now, leave always on
															lOpacity = opacity;
														} else {
															lOpacity = data != ''? icon_opacity_normal:0.0;
														}
														return lOpacity != ''? icon_opacity_normal:0.0;
													}),
					new go.Binding("source", '', function(data){
													var lSource;
													switch (imgSrc){
														case c.data.ouProcessRequestImage:
															lSource = data.outStandingRequestCount > 0?imgSrc:'';
															break;
														case c.data.ouRequestChangeImage:
															lSource = !data.isAdmin?imgSrc:'';
															break;
														case c.data.createSubOUImage:
															lSource = data.isAdmin?imgSrc:'';
															break;
														case c.data.dividerImage:
															lSource = data.isAdmin?imgSrc:'';
															break;
														default:
															lSource = imgSrc;
															break;
													}
													return lSource;
												}),					
				{mouseEnter: function(e, obj) {
					 obj.saveOpacity = obj.opacity;
					 obj.opacity = icon_opacity_hover;
				 },
				 mouseLeave: function(e, obj) {
					 obj.opacity = obj.saveOpacity;
					 obj.saveOpacity = null;
				 },

				 click: function(e, obj) {
					 var objWidget = null;
					 switch (obj.source){
						 case c.data.ouInformationImage:
							 objWidget = JSON.parse(JSON.stringify(informationFormwidgetObject));
							 objWidget.title = c.data.informationModal;
							 objWidget.sys_id = obj.part.data.key;
							 openFormModal(objWidget); 
							 break;
						 case c.data.ouSubOUImage:
							 objWidget = JSON.parse(JSON.stringify(subOUListwidgetObject));
							 objWidget.title = c.data.subOUModal + ': ' + obj.part.data.name;
							 objWidget.filter = objWidget.filter + obj.part.data.key;
							 openListModal(objWidget);
							 break;
						 case c.data.ouMembersImage:							 
							 objWidget = JSON.parse(JSON.stringify(membersOUListwidgetObject));
							 objWidget.title = c.data.memberOUModal + ': ' + obj.part.data.name;
							 objWidget.filter = objWidget.filter + obj.part.data.key; 
							 openListModal(objWidget);
							 break;
						 case c.data.ouContactsImage:
							 objWidget = JSON.parse(JSON.stringify(contactsOUListwidgetObject));
							 objWidget.title = c.data.contactsOUModal + ': ' + obj.part.data.name;
							 objWidget.filter = objWidget.filter + obj.part.data.key;
							 openListModal(objWidget);
							 break;
						 case c.data.ouReportImage:
							 objWidget = JSON.parse(JSON.stringify(OUReportwidgetObject));
							 objWidget.title = c.data.reportOUModal + ' - ' + obj.part.data.name;
							 objWidget.filter = objWidget.filter + obj.part.data.key; 
							 openReportModal(objWidget);
							 break;
						 // STRY0101474
						 case c.data.ouProcessRequestImage:
							 var url = '?id=discover_simple_processing_form&dcu_sys_id=&dcu_table=x_153465_discovert_tasker_requests&dcu_ref=u_ou_parent&dcu_view=&query=u_ou_parent=' + obj.part.data.key + '^u_status=In progress&o=u_requested&d=asc';
							 window.open(url, '_blank');
							 break;
						 case c.data.ouRelatedTasksImage:
							 objWidget = JSON.parse(JSON.stringify(relatedTaskOUListwidgetObject));
							 objWidget.title = c.data.relatedTasksOUModal + ': ' + obj.part.data.name;
							 objWidget.filter = objWidget.filter + obj.part.data.key;
							 openListModal(objWidget);
							 break;

						 case c.data.ouRequestChangeImage:
							 objWidget = JSON.parse(JSON.stringify(requestChangeFormwidgetObject));
							 objWidget.title = c.data.newOURequestChangeModal;
							 objWidget.sys_id = -1; 
							 objWidget.u_ou_parent = obj.part.data.key; 
							 openFormModal(objWidget); 
							 break;

						 case c.data.createSubOUImage:
							 objWidget = JSON.parse(JSON.stringify(createNewFormwidgetObject));
							 objWidget.title = c.data.newSubOUModal;
							 objWidget.sys_id = -1; 
							 objWidget.parent = obj.part.data.key; 
							 openFormModal(objWidget); 
							 break;

						 // STRY0101474 - used for divider
						 default:
							 break;
					 }
					 e.handled = true;
				 }		 
				},
/*					new go.Binding("opacity", "taskManagersValue", 
													function(data){
														return data != ''? 1.0:0.0;
													}
												),
*/												
					{toolTip: toolTiptextHeader!='' ? toolTipDataListJSON(toolTiptextHeader, toolTipBindingList) : ''}
				 );
		return imageJSON;
	}	

	openFormModal = function(widgetObject) {
		spModal.open({
			title: widgetObject.title,
			message: '',
			backdrop: 'static',
//			widget: 'tasker_modal_additional_information',
			widget: 'discovertasker-formtab',
			widgetInput: {
				table: widgetObject.table,
				sys_id: widgetObject.sys_id,
				parent: widgetObject.parent?widgetObject.parent:'',
				u_ou_parent: widgetObject.u_ou_parent?widgetObject.u_ou_parent:'',
				filter: widgetObject.filter?widgetObject.filter:'',
				view: widgetObject.view,
				hideRelatedLists: true,
				omitHeader: 'true',
				hideAttachmentBtn: true,
				isModal: true
			},
			shared: {},
			size: 'lg',
			buttons: []
		});
	};

	openListModal = function(widgetObject) {
		spModal.open({
			title: widgetObject.title,
			message: '',
			backdrop: 'static',

			widget: 'discovertasker-widget-data-table',
			widgetInput: {
				o: widgetObject.o,
				d:  widgetObject.d,
				table: widgetObject.table,
				filter: widgetObject.filter,
				show_new: true,			
				open_new_in_modal: true,
				open_row_details_in_modal: true,
				view: widgetObject.view,
				hideAttachmentBtn: true,
				isModal: true
			},
			size: 'lg',
			buttons: []
		});
	};	

	openReportModal = function(widgetObject) {
//alert('RJ - testing - openReportModal: ' + c.data.baseURL + '?id=organizational_report_page');
		c.modalReportInstance = $uibModal.open({
//			templateUrl:  c.data.baseURL + 'tcp?id=organizational_report_page',
			// STRY0105791
			templateUrl:  c.data.baseURL + c.data.service_portal_url_suffix + '?id=discovertasker_dashboard',
			scope: $scope,
			size: 'lg'
		}).closed.then(function(){
			spUtil.update($scope);
		});


/*
		spModal.open({
			title: widgetObject.title,
			message: '',
			backdrop: 'static',

			widget: 'discovertasker-widget-data-table',
			widgetInput: {
				o: widgetObject.o,
				d:  widgetObject.d,
				table: widgetObject.table,
				filter: widgetObject.filter,
				show_new: true,			
				open_new_in_modal: true,
				open_row_details_in_modal: true,
				view: widgetObject.view,
				hideAttachmentBtn: true,
				isModal: true
			},
			size: 'lg',
			buttons: []
		});
*/		
	};	

	// RJ -ET - Story 4
	// Move this into a fucntion to redraw tree when a new node is selected
	if ($scope.data.id) {
		drawTree();
	}


	function drawTree() {
		if(diagram != undefined){
			diagram.div = null;
			diagram = null;
		}

		var $go = go.GraphObject.make;  // for conciseness in defining templates
		var node_id = "page_map";
		// STRY0072032
		if(!c.data.isSystemTreeOrientationVertical){
			// Horizontal Settings
			diagram =
				$go(go.Diagram, node_id, {
				allowZoom: true,
				// define the layout for the diagram
				layout: $go(go.TreeLayout, { nodeSpacing: 5, layerSpacing: 60 })
			});
		} else{
			diagram =
				$go(go.Diagram, node_id, {
				initialAutoScale: go.Diagram.UniformToFill,
				allowZoom: true,
				// define the layout for the diagram
				layout: $go(go.TreeLayout, { angle:90, nodeSpacing: 5, layerSpacing: 60 })
			});
		}

		diagram.model = new go.TreeModel($scope.data.map);
		var fontStyle = "14px Segoe UI";
		//var font = "13px Helvetica, Arial, sans-serif";
		// Define a simple node template consisting of text followed by an expand/collapse button
		// STRY0072032
		var treeOrientation;
		if(!c.data.isSystemTreeOrientationVertical){
			treeOrientation = "Horizontal";
		} else {
			treeOrientation = "Vertical";
		}
		diagram.nodeTemplate = 
			$go(go.Node, treeOrientation,
					{ selectionAdorned: false,
					 selectionChanged: nodeSelectionChanged,
					 isTreeExpanded: true,
					 isTreeLeaf: true
					},  // this event handler is defined below
					$go(go.Panel, "Auto", 
							$go(go.Shape, "RoundedRectangle", { strokeWidth: 3 },
									new go.Binding("stroke", "isSelected", function(s){
										if (s) 
											return node_selected_border; 
										else 
											return null;}).ofObject(""),
									new go.Binding("fill", "active", function (t){
										if(t)
											return node_active_bg;
										else
											return node_inactive_bg;})
								 ),
							$go(go.Panel, "Vertical", // Vertical Row for Image and Icons
									// ************************************************************************
									// NOTE: the block is FULL SCREEN ONLY
									// ************************************************************************
									$go(go.Panel, "Horizontal",  // Horizontal panel for Image and Icons
											{visible: c.data.isFullScreen},
											$go(go.Panel, "Horizontal", // Horizontal panel for left side to hold Image and move the image to the left
													{visible: c.data.include_poc_avatar},
													{alignment: go.Spot.Left, margin: new go.Margin(5, 3, 5, 10)},
													$go(go.Panel, "Spot", // panel to hold the image clipped into a circle
															{ isClipping: true},
															$go(go.Shape, "Circle", { width: 55, strokeWidth: 0 }), 
															// this is a special picture just for the user
															$go(go.Picture, 
																	{desiredSize: new go.Size(55, 55),
																	 margin: new go.Margin(5, 3, 5, 10),
																	 imageStretch: go.GraphObject.UniformToFill}, 
																	new go.Binding("source", "photo"), 
																	new go.Binding("name","photoName")
																 ) // end image picture object
														 ) // end panel holding circle and picture
												 ),  // end left horizontal panel holding the images

											$go(go.Panel, "Horizontal", // Horizontal panel that contains the icons, set to top right
													{alignment: go.Spot.TopRight, 
													 width: 300,
													 isOpposite: true},
													addImage(c.data.createSubOUImage, c.data.topIconOpacity, '', ''),
													// STRY0101474
													addImage(c.data.dividerImage, c.data.topIconOpacity, '', ''),
													addImage(c.data.ouRelatedTasksImage, c.data.topIconOpacity, '', ''),
													addImage(c.data.ouReportImage, c.data.topIconOpacity, '', ''),
													addImage(c.data.ouContactsImage, c.data.topIconOpacity, '', ''),
													addImage(c.data.ouMembersImage, c.data.topIconOpacity, '', ''),
													addImage(c.data.ouSubOUImage, c.data.topIconOpacity, '', ''),
													addImage(c.data.ouInformationImage, c.data.topIconOpacity, '', ''),
													addImage(c.data.ouRequestChangeImage, c.data.topIconOpacity, '', ''),
													addImage(c.data.ouProcessRequestImage, c.data.topIconOpacity, '', '')
												 ) // end horizontal panel holding the icons	
										 ), // end horizontal Panel holding Images and icons
										// ************************************************************************
										// NOTE: the block is FULL SCREEN ONLY
										// ************************************************************************

									// STRY0108231
									$go(go.Panel,  "Horizontal", // Horizontal panel for Task Manager, Administrator and Text
											{alignment: go.Spot.Left},
											$go(go.Panel, "Horizontal", {alignment: go.Spot.Left},  // Horizontal panel for Task Manager and Administrator
													addImage(c.data.taskManagerImage, 1.0, c.data.titleTaskManagers, "taskManagers"),
													addImage(c.data.Admin16Image, 1.0, c.data.titleOUHierarchyAdministrators, "ouHierarchyAdmins")
												 ),	// end horizonal panel for icons
											$go(go.TextBlock, {alignment: go.Spot.Left, font: fontStyle, stroke: "white", margin: 5,  maxSize: new go.Size(250, 30) },
													new go.Binding("text", "name"))
										 )  // close horizontal panel for Task Manager, Administrator and Text
								 ) // close vertical panel for Task Manager, Administrator and Text
						 ),
					$go("TreeExpanderButton") // this was overkill for small diagrams (shows the icon to expand/collapse)
				 );
		diagram.select(diagram.findNodeForKey(display_id));
		// STRY0072032
		if(!c.data.isSystemTreeOrientationVertical){
			diagram.initialAutoScale=go.Diagram.Uniform;
		}

		diagram.allowVerticalScroll=false;
		// Define a trivial link template with no arrowhead
		diagram.linkTemplate = $go(go.Link, { selectable: false }, $go(go.Shape));  // the link shape

		// Resize the graph container height when the graph changes size
		diagram.addDiagramListener('DocumentBoundsChanged', function(){
			// STRY0096158 - ORG - Template Tree Min Size to avoid cutting off tool tip
			var diagramHeight = parseInt(diagram.documentBounds.height > diagramMinHeight? diagram.documentBounds.height: diagramMinHeight);
			jQuery("#" + node_id).height(diagramHeight);
		})

		// Select the node using the sys_id parameter supplied.
		var node_select = diagram.findNodeForKey(display_id);
		diagram.select(node_select);
	}
	// this event handler is called when the diagram is first ready
	diagram.addDiagramListener("InitialLayoutCompleted", function(e) {
		var node = diagram.findNodeForKey(display_id);
		// and center it and select it
		// STRY0072032
		if(c.data.isSystemTreeOrientationVertical){
			diagram.centerRect(node.actualBounds);
		}
	});

}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES & BRIAN KEENER
// GRAPHICAL TREE FOR PROCESS DEFINITION
//------------------------------------------------------------------------------------------------------------------------
//
// 2.7.0 | 2021-08-22 | raj | STRY0108231 - DIA- Visual Indicators for Organizational Hierarchy Admins- Fix Script
//                                          Changes in Server script, Client Script, HTML
// 2.7.0 | 2021-09-18 | raj | STRY0101474 - Stretch- Add Create Subtask Button to Task Tree View, Template Tree View
//																				Changes in Server script and Client Script
// 2.7.0 | 2021-10-04 | raj | STRY0105791 - Simple Task Forms- Placeholder Story
//																				Changes in Server script and Client Script
// 2.7.0 | 2021-10-07 | raj | DFCT0010565 - Most of the Modals on Tasker are broken
//																				Changes in Server script
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options, gs) {
	data.placeholderMsg = gs.getMessage("Select Task...");
	// STRY0108231
	data.page_id = $sp.getParameter("id");

	// TODO - GET THIS SETTING FROM THE OPTIONS INSTEAD OF LOOKING AT A PAGE ID
	// ONCE COMING FROM OPTIOIN, UPDATE THIS SETTING TO NOT USE PAGE ID, UPDATE
	// ALL PAGES WHERE FULL SCREEN DESIRED TO TRUE AND THE REST SHOULD BE FINE
	data.isFullScreen = data.page_id == 'discovertasker_ouhierarchy_full_screeen';
	// STRY0105791
	data.baseURL = gs.getProperty('glide.servlet.uri');
	// DFCT0010565
	if($sp.getPortalRecord()){
		data.service_portal_url_suffix = $sp.getPortalRecord().getValue('url_suffix');
	} else {
		// TODO: May want to pull default from the form load here
		data.service_portal_url_suffix = '';
	}

	// TODO - GET FROM MESSAGE
	data.informationModal = gs.getMessage('Organizational Unit Information');
	data.subOUModal = gs.getMessage('List of Sub OUs');
	data.memberOUModal = gs.getMessage('List of Members');
	data.contactsOUModal = gs.getMessage('List of Contacts');
	data.reportOUModal = gs.getMessage('OU Reports for ');
	data.relatedTasksOUModal = gs.getMessage('Related Tasks');	
	data.newOURequestChangeModal = gs.getMessage('Tasker - Title - Request Hierarchy Update');
	data.newSubOUModal = gs.getMessage('Create New Sub OU');

	data.OrgFullscreen16 = {"src":'Fullscreen16.svg', "title": gs.getMessage("Open Organizational Hierarchy in full screen in new tab"), "alt": gs.getMessage('Full Screen View')};

	// TODO - ADD TO WIDGET OPTIONS - LEFT OFF FOR NOW
	data.include_poc_avatar = true;

	data.table = 'x_153465_discovert_discover_office_hierarchy';
	data.titleTaskManagers = gs.getMessage('Tasker - Title - TASK MANAGERS');
	data.titleOUHierarchyAdministrators = gs.getMessage('Tasker - Title - OU HIERARCHY ADMINISTRATORS');
	var map = data.map = [];

	data.topParentNeeded = false;
	// STRY0074597 default to true, will change later if input
	data.topOnly = true;
	var count = new GlideAggregate('x_153465_discovert_discover_office_hierarchy');
	count.addQuery('parent', 'null');
	count.addAggregate('COUNT');
	count.query();
	var topHierarchy = 0;
	if(count.next())
		topHierarchy = count.getAggregate('COUNT');

	if (topHierarchy < 1 ) {
		data.topParentNeeded = true;
		return;
	}

	// STRY0072032
	data.isSystemTreeOrientationVertical = new tasking_System_Settings_Scripts().systemControlSetting().VerticalTree;

	//------KTORRES: CHECK IF PARENT OFFICE HIERARCHY HAS BEEN DEFINED BY PROPERTY SETTING
	var defaultIdTopOfficeHierarchy = gs.getProperty("x_153465_discovert.defaultIdTopOfficeHierarchy");
	// RJ -ET - Story 4
	// if the user selected a TOP OU, then rebuild the tree with the selected topOU
	if(input){
		if(input.topOU){
			defaultIdTopOfficeHierarchy = input.topOU;
		}
		// STRY0074597 
		data.topOnly = input.topOnly;
	}
	// RJ -ET - Story 4
	var gr;

	if (defaultIdTopOfficeHierarchy != null) {
		gr = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		if (!gr.get(defaultIdTopOfficeHierarchy)) {
			defaultIdTopOfficeHierarchy = null;
		}
	}

	if (defaultIdTopOfficeHierarchy == null) {
		gr = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		gr.addQuery('parent', 'null');
		gr.query();
		gr.next();
	}

	//--------------------------------------------------------------------------------------

	data.id = gr.getValue('sys_id');
	id = data.id;
	data.title = gr.getValue('office_abbreviation');


	if (!id) {
		data.id = null;
		return;
	}

	// STRY0108231
	data.sys_id=data.id;
	// STRY0101474 
	var isGHA = new	UserInfoScripts().UserHasRole('x_153465_discovert.tasker_organizational_admin');

	var m = getO(gr, null, 1);
	map.push(m);
	getLevel1(map, gr.getValue('sys_id'), m.level);

	// STRY0108231
	// RAJ - NOTE performance, load these 1 time, added if logic.  also moved into fucntion to clean up code
	// --- Get Task Manager Image
	data.taskManagerImage = !data.ouMembersImage?getImage('Tie16.svg'):data.ouMembersImage;
	// --- Get Admin Image
	data.Admin16Image = !data.Admin16Image?getImage('Admin16.svg'):data.Admin16Image;
	// STRY0101474 
	// --- Get Related Tasks Image
	data.ouRequestChangeImage = !data.ouRequestChangeImage?getImage('Request16.svg'):data.ouRequestChangeImage;	
	// --- Get OU Process Request Image
	data.ouProcessRequestImage = !data.ouProcessRequestImage?getImage('ProcessRequest16.svg'):data.ouProcessRequestImage;
	// --- Get OU Information Image
	data.ouInformationImage = !data.ouInformationImage?getImage('Information16.svg'):data.ouInformationImage;
	// --- Get Sub OU Image
	data.ouSubOUImage = !data.ouSubOUImage?getImage('SubOU16.svg'):data.ouSubOUImage;
	// --- Get OU Members Image
	data.ouMembersImage = !data.ouMembersImage?getImage('OUMembers16.svg'):data.ouMembersImage;
	// --- Get OU Contacts Image
	data.ouContactsImage = !data.ouContactsImage?getImage('Contacts16.svg'):data.ouContactsImage;	
	// --- Get OU Reports Image
	data.ouReportImage = !data.ouReportImage?getImage('Reports16.svg'):data.ouReportImage;	
	// STRY0101474
	// --- Get Related Tasks Image
	data.ouRelatedTasksImage = !data.ouRelatedTasksImage?getImage('RelatedTasks16.svg'):data.ouRelatedTasksImage;	
	// --- Get Divider Image
	data.dividerImage = !data.dividerImage?getImage('Divider.svg'):data.dividerImage;	
	// --- Get Create Sub OU Image
	data.createSubOUImage = !data.createSubOUImage?getImage('GenericAddSub16.svg'):data.createSubOUImage;	

	// STRY0101474

	//------------------------------------------------------------------------------------------------------------------------
	function getImage(imageName){
		var grImage = new GlideRecord("db_image");
		var image;
		grImage.addQuery('name',imageName);
		grImage.query();
		if(grImage.next()){
			image=grImage.getDisplayValue();
		}
		return image;
	}

	function getLevel1(map, sys_id) {
		var t = getGR('x_153465_discovert_discover_office_hierarchy', 'parent', sys_id);
		while (t.next()) {
			var c = getO(t, sys_id, 2);
			map.push(c);
			getLeveln(map, t.getValue('sys_id'), c.level);
		}
	}

	function getLeveln(map, sys_id, level) {
		var t = getGR('x_153465_discovert_discover_office_hierarchy', 'parent', sys_id);
		var currentLevel = level + 1;
		while (t.next()) {
			var c = getO(t, sys_id, level);
			map.push(c);
			getLeveln(map, t.getValue('sys_id'), currentLevel);
		}
	}

	function getGR(table, parentField, parentID) {
		var t = new GlideRecordSecure(table);
		t.addQuery(parentField, parentID);
		t.orderBy('level_order');
		t.orderBy('office_name');
		t.query();
		return t;
	}

	// object that goes in the array
	// common vars table, key, sys_id
	function getO(gr, parent, level) {
		var c = {};
			c.table = gr.getTableName();
			c.key = gr.getValue('sys_id');
			c.sys_id = gr.getValue('sys_id');
			c.photo = '';
			c.photoName = '';
			if(gr.u_ou_primary_contact){
				c.photoName = gr.getDisplayValue('u_ou_primary_contact');
				var profile = new GlideRecord("live_profile");
				profile.addQuery("document", gr.u_ou_primary_contact);
				profile.query();
				while (profile.next()){
					var photo = profile.getDisplayValue("photo");
					if (photo.length > 0) {
						c.photo = photo + '?t=small';
					}
				}				
			}

			if (parent)
				c.parent = parent;

			c.name = '' + gr.office_name + '  (' + gr.office_abbreviation + ')';
			c.level = level;
			c.active = gr.active.getDisplayValue();
			// STRY0108231
			var taskManagersDisplayValue = gr.tasking_authorities.getDisplayValue();
			c.taskManagersDisplayValue = taskManagersDisplayValue == null || taskManagersDisplayValue == undefined ? '': taskManagersDisplayValue;
			var taskManagersValue = gr.getValue('tasking_authorities');
			c.taskManagersValue = taskManagersValue == null || taskManagersValue == undefined ? '': taskManagersValue;

		  // load the task managers into the Map
			c.taskManagers = [];
			var aTaskManagers = c.taskManagersDisplayValue.split(',');
			for(var i=0; i<aTaskManagers.length; i++){
				var taskManager = {};
				taskManager.displayName = aTaskManagers[i];
				if(taskManager.displayName != null && taskManager.displayName != undefined && taskManager.displayName != ''){
					c.taskManagers.push(taskManager);					
				}
			}

			var ouHADisplayValue = gr.u_ou_hierarchy_administrators.getDisplayValue();
			c.ouHADisplayValue = ouHADisplayValue == null || ouHADisplayValue == undefined ? '': ouHADisplayValue;
			var ouHAValue = gr.getValue('u_ou_hierarchy_administrators');
			c.ouHAValue = ouHAValue == null || ouHAValue == undefined ? '': ouHAValue;
			// STRY0101474 
			c.outStandingRequestCount = gr.getValue('u_outstanding_request_count')==null?0:parseInt(gr.getValue('u_outstanding_request_count'));
			c.isAdmin = (isGHA || (c.ouHAValue.indexOf(gs.getUserID())>=0));

		  // load the OUHAs into the Map
			c.ouHierarchyAdmins = [];
			var aOUHierarchyAdmins = c.ouHADisplayValue.split(',');
			for(var j=0; j<aOUHierarchyAdmins.length; j++){
				var ouHierarchyAdmin = {};
				ouHierarchyAdmin.displayName = aOUHierarchyAdmins[j];
				if(ouHierarchyAdmin.displayName != null && ouHierarchyAdmin.displayName != undefined && ouHierarchyAdmin.displayName != ''){
					c.ouHierarchyAdmins.push(ouHierarchyAdmin);
				}
			}

			return c;
		}

	//})();
	})($sp, input, data, options, gs);
